import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Check if the X-Enrich-URL header is present
    if 'x-enrich-url' in headers:
        enrich_url = headers['x-enrich-url'][0]['value']
        
        # Validate the URL
        parsed_url = urlparse(enrich_url)
        if parsed_url.scheme not in ['http', 'https']:
            raise ValueError("Invalid URL scheme")
        
        # Fetch additional data
        try:
            response = requests.get(enrich_url, timeout=2)
            response.raise_for_status()
            context_data = response.json()
        except requests.RequestException as e:
            raise RuntimeError(f"Failed to fetch data from {enrich_url}: {e}")
        
        # Add context data to request headers
        request['headers']['x-context-data'] = [{
            'key': 'X-Context-Data',
            'value': json.dumps(context_data)
        }]
    
    return request